import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

export default function Dashboard() {
  const [incidents, setIncidents] = useState([]);

  useEffect(() => {
    const fetchData = () => {
      fetch("http://localhost:8000/incidents")
        .then(res => res.json())
        .then(setIncidents)
        .catch(console.error);
    };

    fetchData();

    // Auto refresh every 5 sec
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ padding: "20px" }}>
      <h2>Incident Dashboard</h2>

      {incidents.length === 0 ? (
        <p>No incidents</p>
      ) : (
        incidents.map(i => (
          <div key={i.id} style={{ border: "1px solid gray", margin: "10px", padding: "10px" }}>
            <p><b>Incident ID:</b> {i.id}</p>
            <p><b>Component:</b> {i.component_id}</p>
            <p><b>Severity:</b> {i.severity}</p>
            <p><b>Status:</b> {i.status}</p>
            <p><b>Signals linked:</b> {i.signal_count}</p>
            <p><b>Start time:</b> {new Date(i.start_time).toLocaleString()}</p>

            <Link to={`/incident/${i.id}`}>View Details</Link>
          </div>
        ))
      )}
    </div>
  );
}
